import React from "react";
import styled from "styled-components";

const ArchivingSource = ({ logo, subtitle, url, paragraph }) => {
  const logoKey = Object.keys(logo)[0];
  const logoValue = Object.values(logo)[0];
  return (
    <StyledRoot>
      <StyledLogo logoKey={logoKey}>
        <img src={logoValue} alt="logo" />
      </StyledLogo>
      <StyledDetail>
        <div>{subtitle}</div>
        <a target="_blank" href={url} rel="noreferrer">
          {url}
        </a>
        <div>{paragraph}</div>
      </StyledDetail>
    </StyledRoot>
  );
};

export default ArchivingSource;

const StyledRoot = styled.div`
  border-style: none;
  display: flex;
  flex-direction: column;
  align-items: center;
  width: 25rem;
  height: 20rem;
  border-radius: 1.8rem;
  background-color: ${({ theme }) => theme.colors.white};
  box-shadow: rgb(0 0 0 / 50%) 0px 0px 3rem 0px;
  margin: 0 1rem;
`;

const StyledLogo = styled.div`
  margin: 1rem 0;
  height: 4rem;
  padding-top: ${(props) => (props.logoKey === "GitHubImg" ? "" : "0.5rem")};
  padding-bottom: ${(props) =>
    props.logoKey === "GitHubImg" ? "0" : "0.5rem"};

  & > img {
    height: 100%;
  }
`;

const StyledDetail = styled.div`
  & > div:first-child {
    display: flex;
    justify-content: center;
    align-items: center;
    font-size: 1.2rem;
    font-weight: 700;
    height: 2rem;
  }

  & > a {
    display: flex;
    justify-content: center;
    color: ${({ theme }) => theme.colors.light_blue};
    font-weight: 700;
  }

  & > div:last-child {
    padding: 2rem 3rem;
    line-height: 1.5;
    text-overflow: ellipsis;
    overflow: hidden;
    display: -webkit-box;
    -webkit-line-clamp: 5;
    -webkit-box-orient: vertical;
    max-width: 30rem;
    max-height: 9.5rem;
  }
`;
