import React, { useEffect, useRef, useState } from "react";
import styled from "styled-components";
import Slide from "./Slide";
import {
  ProjectImg1,
  ProjectImg2,
  ProjectImg3,
  ProjectImg4,
  ProjectImg5,
  ProjectImg6,
  ProjectImg7,
} from "../assets/imgs";

const TOTAL_SLIDES = 6;
const ProjectSource = () => {
  const [currentSlide, setCurrentSlide] = useState(0);
  const slideRef = useRef(null);

  const nextSlide = () => {
    if (currentSlide >= TOTAL_SLIDES) {
      setCurrentSlide(0);
    } else {
      setCurrentSlide(currentSlide + 1);
    }
  };

  const prevSlide = () => {
    if (currentSlide === 0) {
      setCurrentSlide(TOTAL_SLIDES);
    } else {
      setCurrentSlide(currentSlide - 1);
    }
  };

  useEffect(() => {
    slideRef.current.style.transition = "all 0.5s ease-in-out";
    slideRef.current.style.transform = `translateX(-${currentSlide}00%)`;
  }, [currentSlide]);
  return (
    <StyledRoot>
      <Container>
        <SliderContainer ref={slideRef}>
          <Slide img={ProjectImg1} />
          <Slide img={ProjectImg2} />
          <Slide img={ProjectImg3} />
          <Slide img={ProjectImg4} />
          <Slide img={ProjectImg5} />
          <Slide img={ProjectImg6} />
          <Slide img={ProjectImg7} />
        </SliderContainer>
        <StyledButtonWrapper>
          <Button onClick={prevSlide}>Previous Slide</Button>
          <div>{currentSlide + 1}/7</div>
          <Button onClick={nextSlide}>Next Slide</Button>
        </StyledButtonWrapper>
      </Container>
      <StyledDetail>
        <div>점심 메뉴 추천 서비스 COEAT</div>
        <div>
          매일 결정하기 어려운 점심 메뉴, 혹은 저녁 메뉴를 투표를 통해서 결정할
          수 있는 서비스 입니다. 무엇을 먹을지 고민하고, 서로에게 결정권을
          넘기는 경우를 대비하여 투표로 진행됩니다. 먹고 싶은 음식과 먹고 싶지
          않은 음식을 최대 5개까지 고를 수 있고, 같은 링크를 공유하는 사람들끼리
          결과를 집계하여 점심 메뉴를 추천해 드립니다.
        </div>
        <div>
          이 프로젝트에서는 API 서버와 통신하여 방장 뷰와 참여 뷰를 구분하고,
          해당 플로우에 따라 다양한 기능을 구현하는 것에 초점을 두었습니다.
          전반적인 리액트 기술 스택 학습에 도움이 되었고 특히 라우팅과 대표적인
          훅을 확실하게 익힐 수 있었던 프로젝트입니다.
        </div>
        <div>배포 예정중인 서비스 입니다.</div>
      </StyledDetail>
    </StyledRoot>
  );
};

export default ProjectSource;

const StyledRoot = styled.div`
  border-style: none;
  display: flex;
  align-items: center;
  width: 70rem;
  height: 50rem;
  border-radius: 1.8rem;
  background-color: ${({ theme }) => theme.colors.white};
  box-shadow: rgb(0 0 0 / 40%) 0px 0px 1rem 0px;
  margin: 0 1rem;
  padding: 0 1rem;
`;

const Container = styled.div`
  width: 55%;
  overflow: hidden;
`;

const StyledButtonWrapper = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 2rem;
  z-index: 99;

  & > div {
    color: ${({ theme }) => theme.colors.light_blue};
    font-weight: 700;
  }
`;
const Button = styled.button`
  all: unset;
  border: 0.1rem solid coral;
  padding: 0.5em 2em;
  color: ${({ theme }) => theme.colors.light_blue};
  border-radius: 1rem;
  &:hover {
    transition: all 0.3s ease-in-out;
    background-color: ${({ theme }) => theme.colors.light_blue};
    color: #fff;
  }
`;

const SliderContainer = styled.div`
  width: 100%;
  display: flex;
`;

const StyledDetail = styled.div`
  padding: 0 2rem;
  width: 45%;

  & > div:first-child {
    font-size: 2rem;
    color: coral;
    font-weight: 700;
  }
  & > div {
    line-height: 1.8;
    margin-bottom: 2rem;
  }

  & > div:last-child {
    font-weight: 700;
  }
`;
